+    local procedure DeleteSurplusEntriesFromRefOrder(var RequisitionLine: Record "Requisition Line")
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        if (RequisitionLine."Ref. Order Type" = RequisitionLine."Ref. Order Type"::" ") or
+           (RequisitionLine."Ref. Order No." = '')
+        then
+            exit;
+
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+
+        case RequisitionLine."Ref. Order Type" of
+            RequisitionLine."Ref. Order Type"::Purchase:
+                begin
+                    ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+                    ReservationEntry.SetRange("Source Subtype", 1);
+                    ReservationEntry.SetRange("Source ID", RequisitionLine."Ref. Order No.");
+                    ReservationEntry.SetRange("Source Ref. No.", RequisitionLine."Ref. Line No.");
+                end;
+            RequisitionLine."Ref. Order Type"::Transfer:
+                begin
+                    ReservationEntry.SetRange("Source Type", Database::"Transfer Line");
+                    ReservationEntry.SetRange("Source Subtype", 1);
+                    ReservationEntry.SetRange("Source ID", RequisitionLine."Ref. Order No.");
+                    ReservationEntry.SetRange("Source Ref. No.", RequisitionLine."Ref. Line No.");
+                    ReservationEntry.SetRange("Source Prod. Order Line", 0);
+                end;
+        end;
+
+        if ReservationEntry.FindSet() then
+            ReservationEntry.DeleteAll();
+    end;
+
